#define GAMMA 1.4f
#define NDIM 3
#define NNB 4

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM + NDIM)
#define NVAR (VAR_DENSITY_ENERGY + 1)
#define RK 3

inline void compute_flux_contribution(
    const float density,
    const float3 momentum,
    const float density_energy,
    const float pressure,
    const float3 velocity,
    float3* fc_momentum_x,
    float3* fc_momentum_y,
    float3* fc_momentum_z,
    float3* fc_density_energy)
{
    (void)density;

    fc_momentum_x->x = velocity.x * momentum.x + pressure;
    fc_momentum_x->y = velocity.x * momentum.y;
    fc_momentum_x->z = velocity.x * momentum.z;

    fc_momentum_y->x = fc_momentum_x->y;
    fc_momentum_y->y = velocity.y * momentum.y + pressure;
    fc_momentum_y->z = velocity.y * momentum.z;

    fc_momentum_z->x = fc_momentum_x->z;
    fc_momentum_z->y = fc_momentum_y->z;
    fc_momentum_z->z = velocity.z * momentum.z + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy->x = velocity.x * de_p;
    fc_density_energy->y = velocity.y * de_p;
    fc_density_energy->z = velocity.z * de_p;
}

inline float3 compute_velocity(const float density, const float3 momentum)
{
    float3 velocity;
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
    return velocity;
}

inline float compute_speed_sqd(const float3 velocity)
{
    return velocity.x * velocity.x + velocity.y * velocity.y + velocity.z * velocity.z;
}

inline float compute_pressure(const float density, const float density_energy, const float speed_sqd)
{
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

inline float compute_speed_of_sound(const float density, const float pressure)
{
    return sqrt(GAMMA * pressure / density);
}

__kernel void kernel_initialize_variables(
    __global float* variables,
    __global const float* ff_variable,
    const int nelr)
{
    const int i = get_global_id(0);
    for (int j = 0; j < NVAR; j++) {
        variables[i + j * nelr] = ff_variable[j];
    }
}

__kernel void kernel_compute_step_factor(
    __global const float* variables,
    __global const float* areas,
    __global float* step_factors,
    const int nelr)
{
    const int i = get_global_id(0);

    float density = variables[i + VAR_DENSITY * nelr];
    float3 momentum;
    momentum.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
    momentum.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
    momentum.z = variables[i + (VAR_MOMENTUM + 2) * nelr];

    float density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

    float3 velocity = compute_velocity(density, momentum);
    float speed_sqd = compute_speed_sqd(velocity);
    float pressure = compute_pressure(density, density_energy, speed_sqd);
    float speed_of_sound = compute_speed_of_sound(density, pressure);

    step_factors[i] = 0.5f / (sqrt(areas[i]) * (sqrt(speed_sqd) + speed_of_sound));
}

__kernel void kernel_compute_flux(
    __global const int* elements_surrounding_elements,
    __global const float* normals,
    __global const float* variables,
    __global const float* ff_variable,
    __global float* fluxes,
    __global const float* ff_flux_contribution_density_energy,
    __global const float* ff_flux_contribution_momentum_x,
    __global const float* ff_flux_contribution_momentum_y,
    __global const float* ff_flux_contribution_momentum_z,
    const int nelr)
{
    const float smoothing_coefficient = 0.2f;
    const int i = get_global_id(0);

    int j, nb;
    float3 normal;
    float normal_len;
    float factor;

    float density_i = variables[i + VAR_DENSITY * nelr];
    float3 momentum_i;
    momentum_i.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
    momentum_i.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
    momentum_i.z = variables[i + (VAR_MOMENTUM + 2) * nelr];

    float density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

    float3 velocity_i = compute_velocity(density_i, momentum_i);
    float speed_sqd_i = compute_speed_sqd(velocity_i);
    float speed_i = sqrt(speed_sqd_i);
    float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
    float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

    float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
    float3 flux_contribution_i_density_energy;
    compute_flux_contribution(
        density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
        &flux_contribution_i_momentum_x, &flux_contribution_i_momentum_y,
        &flux_contribution_i_momentum_z, &flux_contribution_i_density_energy);

    float flux_i_density = 0.0f;
    float3 flux_i_momentum = (float3)(0.0f, 0.0f, 0.0f);
    float flux_i_density_energy = 0.0f;

    float3 velocity_nb;
    float density_nb, density_energy_nb;
    float3 momentum_nb;
    float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
    float3 flux_contribution_nb_density_energy;
    float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

    for (j = 0; j < NNB; j++) {
        nb = elements_surrounding_elements[i + j * nelr];
        normal.x = normals[i + (j + 0 * NNB) * nelr];
        normal.y = normals[i + (j + 1 * NNB) * nelr];
        normal.z = normals[i + (j + 2 * NNB) * nelr];
        normal_len = sqrt(normal.x * normal.x + normal.y * normal.y + normal.z * normal.z);

        if (nb >= 0) {
            density_nb = variables[nb + VAR_DENSITY * nelr];
            momentum_nb.x = variables[nb + (VAR_MOMENTUM + 0) * nelr];
            momentum_nb.y = variables[nb + (VAR_MOMENTUM + 1) * nelr];
            momentum_nb.z = variables[nb + (VAR_MOMENTUM + 2) * nelr];
            density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

            velocity_nb = compute_velocity(density_nb, momentum_nb);
            speed_sqd_nb = compute_speed_sqd(velocity_nb);
            pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
            speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

            compute_flux_contribution(
                density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
                &flux_contribution_nb_momentum_x, &flux_contribution_nb_momentum_y,
                &flux_contribution_nb_momentum_z, &flux_contribution_nb_density_energy);

            factor = -normal_len * smoothing_coefficient * 0.5f *
                     (speed_i + sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
            flux_i_density += factor * (density_i - density_nb);
            flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
            flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
            flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
            flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

            factor = 0.5f * normal.x;
            flux_i_density += factor * (momentum_nb.x + momentum_i.x);
            flux_i_density_energy += factor * (flux_contribution_nb_density_energy.x + flux_contribution_i_density_energy.x);
            flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.x + flux_contribution_i_momentum_x.x);
            flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.x + flux_contribution_i_momentum_y.x);
            flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.x + flux_contribution_i_momentum_z.x);

            factor = 0.5f * normal.y;
            flux_i_density += factor * (momentum_nb.y + momentum_i.y);
            flux_i_density_energy += factor * (flux_contribution_nb_density_energy.y + flux_contribution_i_density_energy.y);
            flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.y + flux_contribution_i_momentum_x.y);
            flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.y + flux_contribution_i_momentum_y.y);
            flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.y + flux_contribution_i_momentum_z.y);

            factor = 0.5f * normal.z;
            flux_i_density += factor * (momentum_nb.z + momentum_i.z);
            flux_i_density_energy += factor * (flux_contribution_nb_density_energy.z + flux_contribution_i_density_energy.z);
            flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.z + flux_contribution_i_momentum_x.z);
            flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.z + flux_contribution_i_momentum_y.z);
            flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.z + flux_contribution_i_momentum_z.z);
        } else if (nb == -1) {
            flux_i_momentum.x += normal.x * pressure_i;
            flux_i_momentum.y += normal.y * pressure_i;
            flux_i_momentum.z += normal.z * pressure_i;
        } else if (nb == -2) {
            factor = 0.5f * normal.x;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy[0] + flux_contribution_i_density_energy.x);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0] + flux_contribution_i_momentum_x.x);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0] + flux_contribution_i_momentum_y.x);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0] + flux_contribution_i_momentum_z.x);

            factor = 0.5f * normal.y;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy[1] + flux_contribution_i_density_energy.y);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[1] + flux_contribution_i_momentum_x.y);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[1] + flux_contribution_i_momentum_y.y);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[1] + flux_contribution_i_momentum_z.y);

            factor = 0.5f * normal.z;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy[2] + flux_contribution_i_density_energy.z);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[2] + flux_contribution_i_momentum_x.z);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[2] + flux_contribution_i_momentum_y.z);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[2] + flux_contribution_i_momentum_z.z);
        }
    }

    fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
    fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum.x;
    fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum.y;
    fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum.z;
    fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
}

__kernel void kernel_time_step(
    const int j,
    const int nelr,
    __global const float* old_variables,
    __global float* variables,
    __global const float* step_factors,
    __global const float* fluxes)
{
    const int i = get_global_id(0);

    float factor = step_factors[i] / (float)(RK + 1 - j);

    variables[i + VAR_DENSITY * nelr] =
        old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
    variables[i + VAR_DENSITY_ENERGY * nelr] =
        old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
    variables[i + (VAR_MOMENTUM + 0) * nelr] =
        old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
    variables[i + (VAR_MOMENTUM + 1) * nelr] =
        old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
    variables[i + (VAR_MOMENTUM + 2) * nelr] =
        old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
}

#define GAMMA 1.4f
#define NDIM 3
#define NNB 4
#define RK 3

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM + NDIM)
#define NVAR (VAR_DENSITY_ENERGY + 1)

inline void compute_flux_contribution(
    float density,
    float3 momentum,
    float density_energy,
    float pressure,
    float3 velocity,
    float3* fc_momentum_x,
    float3* fc_momentum_y,
    float3* fc_momentum_z,
    float3* fc_density_energy)
{
    (void)density;
    fc_momentum_x->x = velocity.x * momentum.x + pressure;
    fc_momentum_x->y = velocity.x * momentum.y;
    fc_momentum_x->z = velocity.x * momentum.z;

    fc_momentum_y->x = fc_momentum_x->y;
    fc_momentum_y->y = velocity.y * momentum.y + pressure;
    fc_momentum_y->z = velocity.y * momentum.z;

    fc_momentum_z->x = fc_momentum_x->z;
    fc_momentum_z->y = fc_momentum_y->z;
    fc_momentum_z->z = velocity.z * momentum.z + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy->x = velocity.x * de_p;
    fc_density_energy->y = velocity.y * de_p;
    fc_density_energy->z = velocity.z * de_p;
}

inline float3 compute_velocity(float density, float3 momentum)
{
    float3 velocity;
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
    return velocity;
}

inline float compute_speed_sqd(float3 velocity)
{
    return velocity.x * velocity.x + velocity.y * velocity.y + velocity.z * velocity.z;
}

inline float compute_pressure(float density, float density_energy, float speed_sqd)
{
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

inline float compute_speed_of_sound(float density, float pressure)
{
    return sqrt(GAMMA * pressure / density);
}

__kernel void initialize_variables(
    __global float* variables,
    __global const float* ff_variable,
    int nelr)
{
    int i = get_global_id(0);
    for (int j = 0; j < NVAR; j++) {
        variables[i + j * nelr] = ff_variable[j];
    }
}

__kernel void compute_step_factor(
    __global const float* variables,
    __global const float* areas,
    __global float* step_factors,
    int nelr)
{
    int i = get_global_id(0);

    float density = variables[i + VAR_DENSITY * nelr];
    float3 momentum;
    momentum.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
    momentum.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
    momentum.z = variables[i + (VAR_MOMENTUM + 2) * nelr];
    float density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

    float3 velocity = compute_velocity(density, momentum);
    float speed_sqd = compute_speed_sqd(velocity);
    float pressure = compute_pressure(density, density_energy, speed_sqd);
    float speed_of_sound = compute_speed_of_sound(density, pressure);

    step_factors[i] = 0.5f / (sqrt(areas[i]) * (sqrt(speed_sqd) + speed_of_sound));
}

__kernel void compute_flux(
    __global const int* elements_surrounding_elements,
    __global const float* normals,
    __global const float* variables,
    __global const float* ff_variable,
    __global float* fluxes,
    __global const float* ff_flux_contribution_density_energy,
    __global const float* ff_flux_contribution_momentum_x,
    __global const float* ff_flux_contribution_momentum_y,
    __global const float* ff_flux_contribution_momentum_z,
    int nelr)
{
    const float smoothing_coefficient = 0.2f;
    int i = get_global_id(0);

    float density_i = variables[i + VAR_DENSITY * nelr];
    float3 momentum_i;
    momentum_i.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
    momentum_i.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
    momentum_i.z = variables[i + (VAR_MOMENTUM + 2) * nelr];
    float density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

    float3 velocity_i = compute_velocity(density_i, momentum_i);
    float speed_sqd_i = compute_speed_sqd(velocity_i);
    float speed_i = sqrt(speed_sqd_i);
    float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
    float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

    float3 fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z, fc_i_density_energy;
    compute_flux_contribution(
        density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
        &fc_i_momentum_x, &fc_i_momentum_y, &fc_i_momentum_z, &fc_i_density_energy);

    float flux_i_density = 0.0f;
    float3 flux_i_momentum = (float3)(0.0f, 0.0f, 0.0f);
    float flux_i_density_energy = 0.0f;

    for (int j = 0; j < NNB; j++) {
        int nb = elements_surrounding_elements[i + j * nelr];
        float3 normal;
        normal.x = normals[i + (j + 0 * NNB) * nelr];
        normal.y = normals[i + (j + 1 * NNB) * nelr];
        normal.z = normals[i + (j + 2 * NNB) * nelr];
        float normal_len = sqrt(normal.x * normal.x + normal.y * normal.y + normal.z * normal.z);

        if (nb >= 0) {
            float density_nb = variables[nb + VAR_DENSITY * nelr];
            float3 momentum_nb;
            momentum_nb.x = variables[nb + (VAR_MOMENTUM + 0) * nelr];
            momentum_nb.y = variables[nb + (VAR_MOMENTUM + 1) * nelr];
            momentum_nb.z = variables[nb + (VAR_MOMENTUM + 2) * nelr];
            float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

            float3 velocity_nb = compute_velocity(density_nb, momentum_nb);
            float speed_sqd_nb = compute_speed_sqd(velocity_nb);
            float pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
            float speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

            float3 fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z, fc_nb_density_energy;
            compute_flux_contribution(
                density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
                &fc_nb_momentum_x, &fc_nb_momentum_y, &fc_nb_momentum_z, &fc_nb_density_energy);

            float factor = -normal_len * smoothing_coefficient * 0.5f *
                           (speed_i + sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
            flux_i_density += factor * (density_i - density_nb);
            flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
            flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
            flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
            flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

            factor = 0.5f * normal.x;
            flux_i_density += factor * (momentum_nb.x + momentum_i.x);
            flux_i_density_energy += factor * (fc_nb_density_energy.x + fc_i_density_energy.x);
            flux_i_momentum.x += factor * (fc_nb_momentum_x.x + fc_i_momentum_x.x);
            flux_i_momentum.y += factor * (fc_nb_momentum_y.x + fc_i_momentum_y.x);
            flux_i_momentum.z += factor * (fc_nb_momentum_z.x + fc_i_momentum_z.x);

            factor = 0.5f * normal.y;
            flux_i_density += factor * (momentum_nb.y + momentum_i.y);
            flux_i_density_energy += factor * (fc_nb_density_energy.y + fc_i_density_energy.y);
            flux_i_momentum.x += factor * (fc_nb_momentum_x.y + fc_i_momentum_x.y);
            flux_i_momentum.y += factor * (fc_nb_momentum_y.y + fc_i_momentum_y.y);
            flux_i_momentum.z += factor * (fc_nb_momentum_z.y + fc_i_momentum_z.y);

            factor = 0.5f * normal.z;
            flux_i_density += factor * (momentum_nb.z + momentum_i.z);
            flux_i_density_energy += factor * (fc_nb_density_energy.z + fc_i_density_energy.z);
            flux_i_momentum.x += factor * (fc_nb_momentum_x.z + fc_i_momentum_x.z);
            flux_i_momentum.y += factor * (fc_nb_momentum_y.z + fc_i_momentum_y.z);
            flux_i_momentum.z += factor * (fc_nb_momentum_z.z + fc_i_momentum_z.z);
        } else if (nb == -1) {
            flux_i_momentum.x += normal.x * pressure_i;
            flux_i_momentum.y += normal.y * pressure_i;
            flux_i_momentum.z += normal.z * pressure_i;
        } else if (nb == -2) {
            float factor = 0.5f * normal.x;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy[0] + fc_i_density_energy.x);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0] + fc_i_momentum_x.x);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0] + fc_i_momentum_y.x);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0] + fc_i_momentum_z.x);

            factor = 0.5f * normal.y;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy[1] + fc_i_density_energy.y);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[1] + fc_i_momentum_x.y);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[1] + fc_i_momentum_y.y);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[1] + fc_i_momentum_z.y);

            factor = 0.5f * normal.z;
            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
            flux_i_density_energy += factor * (ff_flux_contribution_density_energy[2] + fc_i_density_energy.z);
            flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[2] + fc_i_momentum_x.z);
            flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[2] + fc_i_momentum_y.z);
            flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[2] + fc_i_momentum_z.z);
        }
    }

    fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
    fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum.x;
    fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum.y;
    fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum.z;
    fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
}

__kernel void time_step(
    int j,
    int nelr,
    __global const float* old_variables,
    __global float* variables,
    __global const float* step_factors,
    __global const float* fluxes)
{
    int i = get_global_id(0);
    float factor = step_factors[i] / (float)(RK + 1 - j);

    variables[i + VAR_DENSITY * nelr] =
        old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
    variables[i + VAR_DENSITY_ENERGY * nelr] =
