    /* horizontal-high columns -> HL / HH */
    for (int x = 0; x < highW; x++) {
        for (int ly = 0; ly < lowH; ly++) {
            int evenY = ly << 1;
            int v = vert_low_from_rowpacked(output, sx, sy, lowW, 1, x, evenY);
