static inline void heartwall_core(
	int frame_no,
	params_common d_common,
	__global fp* d_frame,

	__global int* d_endoRow,
	__global int* d_endoCol,
	__global int* d_tEndoRowLoc,
	__global int* d_tEndoColLoc,

	__global int* d_epiRow,
	__global int* d_epiCol,
	__global int* d_tEpiRowLoc,
	__global int* d_tEpiColLoc,

	__global fp* d_endoT,
	__global fp* d_epiT,

	__global fp* d_in2,
	__global fp* d_conv,
	__global fp* d_in2_pad_cumv,
	__global fp* d_in2_pad_cumv_sel,
	__global fp* d_in2_sub_cumh,
	__global fp* d_in2_sub_cumh_sel,
	__global fp* d_in2_sub2,
	__global fp* d_in2_sqr,
	__global fp* d_in2_sqr_sub2,
	__global fp* d_in_sqr,
	__global fp* d_tMask,
	__global fp* d_mask_conv
){
	int bx = get_group_id(0);
	int tx = get_local_id(0);

	__local float in_partial_sum[51];
	__local float in_sqr_partial_sum[51];
	__local float in_final_sum;
	__local float in_sqr_final_sum;
	__local float denomT;
	__local float par_max_val[131];
	__local int par_max_coo[131];
	__local float d_in_mod_temp[2601];

	int point_no;
	__global int* d_Row;
	__global int* d_Col;
	__global int* d_tRowLoc;
	__global int* d_tColLoc;
	__global fp* d_Tbase;

	if (bx < d_common.endoPoints) {
		point_no = bx;
		d_Row = d_endoRow;
		d_Col = d_endoCol;
		d_tRowLoc = d_tEndoRowLoc;
		d_tColLoc = d_tEndoColLoc;
		d_Tbase = d_endoT;
	} else {
		point_no = bx - d_common.endoPoints;
		d_Row = d_epiRow;
		d_Col = d_epiCol;
		d_tRowLoc = d_tEpiRowLoc;
		d_tColLoc = d_tEpiColLoc;
		d_Tbase = d_epiT;
	}

	int in_pointer = point_no * d_common.in_elem;
	__global fp* d_in = d_Tbase + in_pointer;

	int off_in2 = bx * d_common.in2_elem;
	int off_conv = bx * d_common.conv_elem;
	int off_in2_pad_cumv = bx * d_common.in2_pad_cumv_elem;
	int off_in2_pad_cumv_sel = bx * d_common.in2_pad_cumv_sel_elem;
	int off_in2_sub_cumh = bx * d_common.in2_sub_cumh_elem;
	int off_in2_sub_cumh_sel = bx * d_common.in2_sub_cumh_sel_elem;
	int off_in2_sub2 = bx * d_common.in2_sub2_elem;
	int off_in2_sqr = bx * d_common.in2_sqr_elem;
	int off_in2_sqr_sub2 = bx * d_common.in2_sqr_sub2_elem;
	int off_in_sqr = bx * d_common.in_sqr_elem;
	int off_tMask = bx * d_common.tMask_elem;
	int off_mask_conv = bx * d_common.mask_conv_elem;

	int rot_row, rot_col;
	int in2_rowlow, in2_collow;
	int ic, jc, jp1, ja1, ja2, ip1, ia1, ia2, ja, jb, ia, ib;
	float s;
	int i, j, row, col, ori_row, ori_col, position, pos_ori;
	float sum, temp, temp2;
	int location, cent, tMask_row, tMask_col;
	float largest_value_current = 0.0f, largest_value = 0.0f;
	int largest_coordinate_current = 0, largest_coordinate = 0;
	float fin_max_val = 0.0f;
	int fin_max_coo = 0;
	int largest_row, largest_col, offset_row, offset_col;
	int pointer, ori_pointer, loc_pointer;
	int ei_new;
	float mean, mean_sqr, variance, deviation;

	if (frame_no == 0) {
		ei_new = tx;
		if (ei_new == 0) {
			pointer = point_no * d_common.no_frames + frame_no;
			d_tRowLoc[pointer] = d_Row[point_no];
			d_tColLoc[pointer] = d_Col[point_no];
		}

		ei_new = tx;
		while (ei_new < d_common.in_elem) {
			row = (ei_new + 1) % d_common.in_rows - 1;
			col = (ei_new + 1) / d_common.in_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in_rows == 0) {
				row = d_common.in_rows - 1;
				col = col - 1;
			}
			ori_row = d_Row[point_no] - 25 + row - 1;
			ori_col = d_Col[point_no] - 25 + col - 1;
			ori_pointer = ori_col * d_common.frame_rows + ori_row;
			d_in[col * d_common.in_rows + row] = d_frame[ori_pointer];
			ei_new += NUMBER_THREADS;
		}
	}

	if (frame_no != 0) {
		in2_rowlow = d_Row[point_no] - d_common.sSize;
		in2_collow = d_Col[point_no] - d_common.sSize;

		ei_new = tx;
		while (ei_new < d_common.in2_elem) {
			row = (ei_new + 1) % d_common.in2_rows - 1;
			col = (ei_new + 1) / d_common.in2_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_rows == 0) {
				row = d_common.in2_rows - 1;
				col = col - 1;
			}
			ori_row = row + in2_rowlow - 1;
			ori_col = col + in2_collow - 1;
			d_in2[off_in2 + ei_new] = d_frame[ori_col * d_common.frame_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in_elem) {
			row = (ei_new + 1) % d_common.in_rows - 1;
			col = (ei_new + 1) / d_common.in_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in_rows == 0) {
				row = d_common.in_rows - 1;
				col = col - 1;
			}
			rot_row = (d_common.in_rows - 1) - row;
			rot_col = (d_common.in_rows - 1) - col;
			d_in_mod_temp[ei_new] = d_in[rot_col * d_common.in_rows + rot_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.conv_elem) {
			ic = (ei_new + 1) % d_common.conv_rows;
			jc = (ei_new + 1) / d_common.conv_rows + 1;
			if ((ei_new + 1) % d_common.conv_rows == 0) {
				ic = d_common.conv_rows;
				jc = jc - 1;
			}
			j = jc + d_common.joffset;
			jp1 = j + 1;
			ja1 = (d_common.in2_cols < jp1) ? (jp1 - d_common.in2_cols) : 1;
			ja2 = (d_common.in_cols < j) ? d_common.in_cols : j;

			i = ic + d_common.ioffset;
			ip1 = i + 1;
			ia1 = (d_common.in2_rows < ip1) ? (ip1 - d_common.in2_rows) : 1;
			ia2 = (d_common.in_rows < i) ? d_common.in_rows : i;

			s = 0.0f;
			for (ja = ja1; ja <= ja2; ja++) {
				jb = jp1 - ja;
				for (ia = ia1; ia <= ia2; ia++) {
					ib = ip1 - ia;
					s += d_in_mod_temp[d_common.in_rows * (ja - 1) + ia - 1] *
					     d_in2[off_in2 + d_common.in2_rows * (jb - 1) + ib - 1];
				}
			}
			d_conv[off_conv + ei_new] = s;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_pad_cumv_elem) {
			row = (ei_new + 1) % d_common.in2_pad_cumv_rows - 1;
			col = (ei_new + 1) / d_common.in2_pad_cumv_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_pad_cumv_rows == 0) {
				row = d_common.in2_pad_cumv_rows - 1;
				col = col - 1;
			}
			if (row > (d_common.in2_pad_add_rows - 1) &&
			    row < (d_common.in2_pad_add_rows + d_common.in2_rows) &&
			    col > (d_common.in2_pad_add_cols - 1) &&
			    col < (d_common.in2_pad_add_cols + d_common.in2_cols)) {
				ori_row = row - d_common.in2_pad_add_rows;
				ori_col = col - d_common.in2_pad_add_cols;
				d_in2_pad_cumv[off_in2_pad_cumv + ei_new] = d_in2[off_in2 + ori_col * d_common.in2_rows + ori_row];
			} else {
				d_in2_pad_cumv[off_in2_pad_cumv + ei_new] = 0.0f;
			}
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_pad_cumv_cols) {
			pos_ori = ei_new * d_common.in2_pad_cumv_rows;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + d_common.in2_pad_cumv_rows; position++) {
				d_in2_pad_cumv[off_in2_pad_cumv + position] += sum;
				sum = d_in2_pad_cumv[off_in2_pad_cumv + position];
			}
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_pad_cumv_sel_elem) {
			row = (ei_new + 1) % d_common.in2_pad_cumv_sel_rows - 1;
			col = (ei_new + 1) / d_common.in2_pad_cumv_sel_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_pad_cumv_sel_rows == 0) {
				row = d_common.in2_pad_cumv_sel_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
			ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
			d_in2_pad_cumv_sel[off_in2_pad_cumv_sel + ei_new] = d_in2_pad_cumv[off_in2_pad_cumv + ori_col * d_common.in2_pad_cumv_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_elem) {
			row = (ei_new + 1) % d_common.in2_sub_cumh_rows - 1;
			col = (ei_new + 1) / d_common.in2_sub_cumh_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_sub_cumh_rows == 0) {
				row = d_common.in2_sub_cumh_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
			ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
			d_in2_sub_cumh[off_in2_sub_cumh + ei_new] = d_in2_pad_cumv[off_in2_pad_cumv + ori_col * d_common.in2_pad_cumv_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_elem) {
			d_in2_sub_cumh[off_in2_sub_cumh + ei_new] =
				d_in2_pad_cumv_sel[off_in2_pad_cumv_sel + ei_new] - d_in2_sub_cumh[off_in2_sub_cumh + ei_new];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_rows) {
			pos_ori = ei_new;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + d_common.in2_sub_cumh_elem; position += d_common.in2_sub_cumh_rows) {
				d_in2_sub_cumh[off_in2_sub_cumh + position] += sum;
				sum = d_in2_sub_cumh[off_in2_sub_cumh + position];
			}
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_sel_elem) {
			row = (ei_new + 1) % d_common.in2_sub_cumh_sel_rows - 1;
			col = (ei_new + 1) / d_common.in2_sub_cumh_sel_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_sub_cumh_sel_rows == 0) {
				row = d_common.in2_sub_cumh_sel_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
			ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
			d_in2_sub_cumh_sel[off_in2_sub_cumh_sel + ei_new] = d_in2_sub_cumh[off_in2_sub_cumh + ori_col * d_common.in2_sub_cumh_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub2_elem) {
			row = (ei_new + 1) % d_common.in2_sub2_rows - 1;
			col = (ei_new + 1) / d_common.in2_sub2_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_sub2_rows == 0) {
				row = d_common.in2_sub2_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
			ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
			d_in2_sub2[off_in2_sub2 + ei_new] = d_in2_sub_cumh[off_in2_sub_cumh + ori_col * d_common.in2_sub_cumh_rows + ori_row];
