				d_in2_sub_cumh_sel[off_in2_sub_cumh_sel + ei_new] - d_in2_sub2[off_in2_sub2 + ei_new];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sqr_elem) {
			temp = d_in2[off_in2 + ei_new];
