		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_pad_cumv_elem) {
			row = (ei_new + 1) % d_common.in2_pad_cumv_rows - 1;
			col = (ei_new + 1) / d_common.in2_pad_cumv_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_pad_cumv_rows == 0) {
				row = d_common.in2_pad_cumv_rows - 1;
				col = col - 1;
			}
			if (row > (d_common.in2_pad_add_rows - 1) &&
			    row < (d_common.in2_pad_add_rows + d_common.in2_sqr_rows) &&
			    col > (d_common.in2_pad_add_cols - 1) &&
			    col < (d_common.in2_pad_add_cols + d_common.in2_sqr_cols)) {
				ori_row = row - d_common.in2_pad_add_rows;
				ori_col = col - d_common.in2_pad_add_cols;
				d_in2_pad_cumv[off_in2_pad_cumv + ei_new] = d_in2_sqr[off_in2_sqr + ori_col * d_common.in2_sqr_rows + ori_row];
			} else {
				d_in2_pad_cumv[off_in2_pad_cumv + ei_new] = 0.0f;
			}
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_pad_cumv_cols) {
			pos_ori = ei_new * d_common.in2_pad_cumv_rows;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + d_common.in2_pad_cumv_rows; position++) {
				d_in2_pad_cumv[off_in2_pad_cumv + position] += sum;
				sum = d_in2_pad_cumv[off_in2_pad_cumv + position];
			}
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_pad_cumv_sel_elem) {
			row = (ei_new + 1) % d_common.in2_pad_cumv_sel_rows - 1;
			col = (ei_new + 1) / d_common.in2_pad_cumv_sel_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_pad_cumv_sel_rows == 0) {
				row = d_common.in2_pad_cumv_sel_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
			ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
			d_in2_pad_cumv_sel[off_in2_pad_cumv_sel + ei_new] = d_in2_pad_cumv[off_in2_pad_cumv + ori_col * d_common.in2_pad_cumv_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_elem) {
			row = (ei_new + 1) % d_common.in2_sub_cumh_rows - 1;
			col = (ei_new + 1) / d_common.in2_sub_cumh_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_sub_cumh_rows == 0) {
				row = d_common.in2_sub_cumh_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
			ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
			d_in2_sub_cumh[off_in2_sub_cumh + ei_new] = d_in2_pad_cumv[off_in2_pad_cumv + ori_col * d_common.in2_pad_cumv_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_elem) {
			d_in2_sub_cumh[off_in2_sub_cumh + ei_new] =
				d_in2_pad_cumv_sel[off_in2_pad_cumv_sel + ei_new] - d_in2_sub_cumh[off_in2_sub_cumh + ei_new];
			ei_new += NUMBER_THREADS;
		}

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_rows) {
			pos_ori = ei_new;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + d_common.in2_sub_cumh_elem; position += d_common.in2_sub_cumh_rows) {
				d_in2_sub_cumh[off_in2_sub_cumh + position] += sum;
				sum = d_in2_sub_cumh[off_in2_sub_cumh + position];
			}
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub_cumh_sel_elem) {
			row = (ei_new + 1) % d_common.in2_sub_cumh_sel_rows - 1;
			col = (ei_new + 1) / d_common.in2_sub_cumh_sel_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_sub_cumh_sel_rows == 0) {
				row = d_common.in2_sub_cumh_sel_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
			ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
			d_in2_sub_cumh_sel[off_in2_sub_cumh_sel + ei_new] = d_in2_sub_cumh[off_in2_sub_cumh + ori_col * d_common.in2_sub_cumh_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub2_elem) {
			row = (ei_new + 1) % d_common.in2_sub2_rows - 1;
			col = (ei_new + 1) / d_common.in2_sub2_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in2_sub2_rows == 0) {
				row = d_common.in2_sub2_rows - 1;
				col = col - 1;
			}
			ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
			ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
			d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new] = d_in2_sub_cumh[off_in2_sub_cumh + ori_col * d_common.in2_sub_cumh_rows + ori_row];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub2_elem) {
			d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new] =
				d_in2_sub_cumh_sel[off_in2_sub_cumh_sel + ei_new] - d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub2_elem) {
			temp = d_in2_sub2[off_in2_sub2 + ei_new];
			temp2 = d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new] - (temp * temp / d_common.in_elem);
			if (temp2 < 0.0f) temp2 = 0.0f;
			d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new] = sqrt(temp2);
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in_sqr_elem) {
			temp = d_in[ei_new];
			d_in_sqr[off_in_sqr + ei_new] = temp * temp;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in_cols) {
			sum = 0.0f;
			for (i = 0; i < d_common.in_rows; i++) sum += d_in[ei_new * d_common.in_rows + i];
			in_partial_sum[ei_new] = sum;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in_sqr_rows) {
			sum = 0.0f;
			for (i = 0; i < d_common.in_sqr_cols; i++) sum += d_in_sqr[off_in_sqr + ei_new + d_common.in_sqr_rows * i];
			in_sqr_partial_sum[ei_new] = sum;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		if (tx == 0) {
			in_final_sum = 0.0f;
			for (i = 0; i < d_common.in_cols; i++) in_final_sum += in_partial_sum[i];
		} else if (tx == 1) {
			in_sqr_final_sum = 0.0f;
			for (i = 0; i < d_common.in_sqr_cols; i++) in_sqr_final_sum += in_sqr_partial_sum[i];
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		if (tx == 0) {
			mean = in_final_sum / d_common.in_elem;
			mean_sqr = mean * mean;
			variance = (in_sqr_final_sum / d_common.in_elem) - mean_sqr;
			deviation = sqrt(variance);
			denomT = sqrt((float)(d_common.in_elem - 1)) * deviation;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub2_elem) {
			d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new] *= denomT;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.conv_elem) {
			d_conv[off_conv + ei_new] = d_conv[off_conv + ei_new] - d_in2_sub2[off_in2_sub2 + ei_new] * in_final_sum / d_common.in_elem;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.in2_sub2_elem) {
			d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new] =
				d_conv[off_conv + ei_new] / d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new];
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		cent = d_common.sSize + d_common.tSize + 1;
		if (frame_no == 0) {
			tMask_row = cent + d_Row[point_no] - d_Row[point_no] - 1;
			tMask_col = cent + d_Col[point_no] - d_Col[point_no] - 1;
		} else {
			pointer = frame_no - 1 + point_no * d_common.no_frames;
			tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
			tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;
		}

		ei_new = tx;
		while (ei_new < d_common.tMask_elem) {
			location = tMask_col * d_common.tMask_rows + tMask_row;
			d_tMask[off_tMask + ei_new] = (ei_new == location) ? 1.0f : 0.0f;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.mask_conv_elem) {
			ic = (ei_new + 1) % d_common.mask_conv_rows;
			jc = (ei_new + 1) / d_common.mask_conv_rows + 1;
			if ((ei_new + 1) % d_common.mask_conv_rows == 0) {
				ic = d_common.mask_conv_rows;
				jc = jc - 1;
			}

			j = jc + d_common.mask_conv_joffset;
			jp1 = j + 1;
			ja1 = (d_common.mask_cols < jp1) ? (jp1 - d_common.mask_cols) : 1;
			ja2 = (d_common.tMask_cols < j) ? d_common.tMask_cols : j;

			i = ic + d_common.mask_conv_ioffset;
			ip1 = i + 1;
			ia1 = (d_common.mask_rows < ip1) ? (ip1 - d_common.mask_rows) : 1;
			ia2 = (d_common.tMask_rows < i) ? d_common.tMask_rows : i;

			s = 0.0f;
			for (ja = ja1; ja <= ja2; ja++) {
				jb = jp1 - ja;
				for (ia = ia1; ia <= ia2; ia++) {
					ib = ip1 - ia;
					s += d_tMask[off_tMask + d_common.tMask_rows * (ja - 1) + ia - 1];
				}
			}
			d_mask_conv[off_mask_conv + ei_new] = d_in2_sqr_sub2[off_in2_sqr_sub2 + ei_new] * s;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		ei_new = tx;
		while (ei_new < d_common.mask_conv_rows) {
			for (i = 0; i < d_common.mask_conv_cols; i++) {
				largest_coordinate_current = ei_new * d_common.mask_conv_rows + i;
				largest_value_current = fabs(d_mask_conv[off_mask_conv + largest_coordinate_current]);
				if (largest_value_current > largest_value) {
					largest_coordinate = largest_coordinate_current;
					largest_value = largest_value_current;
				}
			}
			par_max_coo[ei_new] = largest_coordinate;
			par_max_val[ei_new] = largest_value;
			ei_new += NUMBER_THREADS;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		if (tx == 0) {
			for (i = 0; i < d_common.mask_conv_rows; i++) {
				if (par_max_val[i] > fin_max_val) {
					fin_max_val = par_max_val[i];
					fin_max_coo = par_max_coo[i];
				}
			}

			largest_row = (fin_max_coo + 1) % d_common.mask_conv_rows - 1;
			largest_col = (fin_max_coo + 1) / d_common.mask_conv_rows;
			if ((fin_max_coo + 1) % d_common.mask_conv_rows == 0) {
				largest_row = d_common.mask_conv_rows - 1;
				largest_col = largest_col - 1;
			}

			largest_row = largest_row + 1;
			largest_col = largest_col + 1;
			offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
			offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
			pointer = frame_no + point_no * d_common.no_frames;
			d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
			d_tColLoc[pointer] = d_Col[point_no] + offset_col;
		}
		barrier(CLK_LOCAL_MEM_FENCE);
	}

	if (frame_no != 0 && (frame_no % 10) == 0) {
		loc_pointer = point_no * d_common.no_frames + frame_no;
		d_Row[point_no] = d_tRowLoc[loc_pointer];
		d_Col[point_no] = d_tColLoc[loc_pointer];

		ei_new = tx;
		while (ei_new < d_common.in_elem) {
			row = (ei_new + 1) % d_common.in_rows - 1;
			col = (ei_new + 1) / d_common.in_rows + 1 - 1;
			if ((ei_new + 1) % d_common.in_rows == 0) {
				row = d_common.in_rows - 1;
				col = col - 1;
			}
			ori_row = d_Row[point_no] - 25 + row - 1;
			ori_col = d_Col[point_no] - 25 + col - 1;
			ori_pointer = ori_col * d_common.frame_rows + ori_row;
			d_in[ei_new] = d_common.alpha * d_in[ei_new] + (1.0f - d_common.alpha) * d_frame[ori_pointer];
			ei_new += NUMBER_THREADS;
		}
	}
}

