    int lsize = (int)get_local_size(0);
    int stride = K + 1;

    for (int i = lid; i < dim; i += lsize) {
        x_coord_local[i] = coord_d[i * num + (int)x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (tid < num) {
        __global float *lower = &work_mem_d[tid * stride];

        float x_cost = d_dist_point_to_x(tid, x, num, dim, coord_d, x_coord_local) * p[tid].weight;

        if (x_cost < p[tid].cost) {
            switch_membership_d[tid] = (char)'1';
            lower[K] += x_cost - p[tid].cost;
        } else {
            lower[center_table_d[(int)p[tid].assign]] += p[tid].cost - x_cost;
        }
    }
}

typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

inline float d_dist(const int p1, const long p2, const int num, const int dim, __global const float *coord_d) {
    float retval = 0.0f;
    int p2i = (int)p2;
    for (int i = 0; i < dim; i++) {
        float tmp = coord_d[i * num + p1] - coord_d[i * num + p2i];
        retval += tmp * tmp;
    }
    return retval;
}

__kernel void kernel_unused() {
}

__kernel void kernel_compute_cost(
    __global const Point_Struct *p,
    __global const float *coord_d,
    __global float *work_mem_d,
    __global const int *center_table_d,
    __global char *switch_membership_d,
    __local float *coord_s,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    (void)coord_s;

    const int tid = (int)get_global_id(0);
    if (tid < num) {
        const int stride = K + 1;
        __global float *lower = &work_mem_d[tid * stride];

        float x_cost = d_dist(tid, x, num, dim, coord_d) * p[tid].weight;

        if (x_cost < p[tid].cost) {
            switch_membership_d[tid] = '1';
            lower[K] += x_cost - p[tid].cost;
        } else {
            int cidx = center_table_d[(int)p[tid].assign];
            lower[cidx] += p[tid].cost - x_cost;
        }
    }
}
